description:
Add caching for CompiledSignature to avoid re-compiling on every call. Use the existing Cache infrastructure.

Location: crates/dspy-rs/src/signature/compiled.rs and/or adapter/chat.rs

```rust
use crate::utils::cache::Cache;
use std::any::TypeId;

/// Global cache for compiled signatures
static COMPILED_SIGNATURE_CACHE: LazyLock<Cache<TypeId, Arc<dyn Any + Send + Sync>>> = 
    LazyLock::new(|| Cache::new());

impl<T: Signature + 'static> CompileExt for T {
    fn compile() -> CompiledSignature<Self> {
        let type_id = TypeId::of::<Self>();

        COMPILED_SIGNATURE_CACHE
            .get_or_insert(type_id, || {
                let compiled = compile_signature_inner::<Self>();
                Arc::new(compiled) as Arc<dyn Any + Send + Sync>
            })
            .downcast_ref::<CompiledSignature<Self>>()
            .expect('cached signature has wrong type')
            .clone()
    }
}
```

Alternative: use schema_fingerprint as cache key if you want invalidation on type changes (useful for hot-reload scenarios).

For now, simple TypeId-based caching is sufficient since types are compile-time constants.
